  1→
  2→import React, { useState } from 'react';
  3→import { Shield, Zap, Globe, Check, Lock, ChevronRight, Server, Sparkles, CreditCard, Loader2, RefreshCw, ArrowLeft, Search, Filter, Star, ExternalLink, TrendingUp, ArrowRight, Plus } from 'lucide-react';
  4→import { AnalysisResult, CategoryScore, Recommendation } from '../types';
  5→
  6→interface DirectoryProps {
  7→  onBack: () => void;
  8→  onViewEntity: (result: AnalysisResult) => void;
  9→  onNavigateToPlan: () => void;
 10→}
 11→
 12→// Données simulées pour l'annuaire public
 13→const DIRECTORY_DATA = [
 14→  { id: 1, name: 'Stripe', sector: 'Fintech', aeoScore: 98, status: 'Elite', verified: true, desc: "Infrastructure de paiement pour internet." },
 15→  { id: 2, name: 'Linear', sector: 'SaaS B2B', aeoScore: 94, status: 'Elite', verified: true, desc: "Outil de gestion de projet moderne." },
 16→  { id: 3, name: 'Algolia', sector: 'Search API', aeoScore: 89, status: 'Premium', verified: true, desc: "API de recherche rapide et pertinente." },
 17→  { id: 4, name: 'Qonto', sector: 'Banque', aeoScore: 88, status: 'Premium', verified: true, desc: "La néobanque des PME et indépendants." },
 18→  { id: 5, name: 'Doctolib', sector: 'Santé', aeoScore: 85, status: 'Premium', verified: true, desc: "Plateforme de prise de rendez-vous médicaux." },
 19→  { id: 6, name: 'Alan', sector: 'Assurance', aeoScore: 92, status: 'Elite', verified: true, desc: "L'assurance santé simple et transparente." },
 20→  { id: 7, name: 'Swile', sector: 'RH', aeoScore: 78, status: 'Standard', verified: true, desc: "La carte titre-restaurant nouvelle génération." },
 21→  { id: 8, name: 'Payfit', sector: 'RH Tech', aeoScore: 81, status: 'Premium', verified: true, desc: "Gestion de la paie simplifiée." },
 22→];
 23→
 24→const Directory: React.FC<DirectoryProps> = ({ onBack, onViewEntity, onNavigateToPlan }) => {
 25→  const [viewMode, setViewMode] = useState<'browse' | 'join'>('browse'); // 'browse' = Annuaire Public, 'join' = Tunnel d'achat
 26→  const [step, setStep] = useState<'intro' | 'form' | 'payment' | 'success'>('intro');
 27→  const [isProcessing, setIsProcessing] = useState(false);
 28→  const [searchTerm, setSearchTerm] = useState('');
 29→  const [selectedFilter, setSelectedFilter] = useState('All');
 30→  
 31→  const [formData, setFormData] = useState({
 32→    companyName: '',
 33→    website: '',
 34→    description: '',
 35→    industry: '',
 36→    competitors: ''
 37→  });
 38→
 39→  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
 40→    setFormData({ ...formData, [e.target.name]: e.target.value });
 41→  };
 42→
 43→  const handleFormSubmit = (e: React.FormEvent) => {
 44→    e.preventDefault();
 45→    setStep('payment');
 46→  };
 47→
 48→  const handlePayment = async () => {
 49→    setIsProcessing(true);
 50→    await new Promise(resolve => setTimeout(resolve, 3000));
 51→    setIsProcessing(false);
 52→    setStep('success');
 53→  };
 54→
 55→  const filteredDirectory = DIRECTORY_DATA.filter(item => {
 56→    const matchesSearch = item.name.toLowerCase().includes(searchTerm.toLowerCase()) || item.desc.toLowerCase().includes(searchTerm.toLowerCase());
 57→    const matchesFilter = selectedFilter === 'All' || item.sector === selectedFilter;
 58→    return matchesSearch && matchesFilter;
 59→  });
 60→
 61→  const uniqueSectors = ['All', ...Array.from(new Set(DIRECTORY_DATA.map(item => item.sector)))];
 62→
 63→  // --- GENERATE MOCK ANALYSIS BASED ON DIRECTORY ITEM ---
 64→  const generateMockAnalysis = (item: typeof DIRECTORY_DATA[0]): AnalysisResult => {
 65→    const url = `https://www.${item.name.toLowerCase()}.com`;
 66→    const score = item.aeoScore;
 67→    
 68→    // Simulate high scores for Elite items
 69→    const isElite = score > 90;
 70→    
 71→    const categories: Record<string, CategoryScore> = {
 72→        technical: {
 73→            name: "Infrastructure Technique",
 74→            score: isElite ? 95 : 85,
 75→            weight: 10,
 76→            items: [{ status: 'success', message: 'Temps de réponse TTFB < 100ms' }, { status: 'success', message: 'Rendu SSR optimisé' }]
 77→        },
 78→        entity: {
 79→            name: "Autorité Entité",
 80→            score: score,
 81→            weight: 10,
 82→            items: [
 83→                { status: 'success', message: 'Fiche Knowledge Graph détectée' },
 84→                { status: isElite ? 'success' : 'warning', message: isElite ? 'Page "À propos" détaillée' : 'Page "À propos" perfectible' }
 85→            ]
 86→        },
 87→        semantic: {
 88→            name: "Structure Sémantique",
 89→            score: score - 5,
 90→            weight: 10,
 91→            items: [
 92→                { status: 'success', message: 'Balisage Schema.org Organization valide' },
 93→                { status: 'success', message: 'Structure Hn logique' }
 94→            ]
 95→        },
 96→        content: {
 97→            name: "Profondeur Contenu",
 98→            score: score - 2,
 99→            weight: 10,
100→            items: [{ status: 'success', message: 'Densité entités nommées élevée' }]
101→        }
102→    };
103→
104→    return {
105→        url,
106→        timestamp: new Date().toISOString(),
107→        globalScore: score,
108→        categories,
109→        recommendations: [], // Pas de recommendations en vue publique
110→        aiCitation: {
111→            before: `Je n'ai pas d'informations précises sur ${item.name}.`,
112→            after: `D'après ses données structurées, ${item.name} est un leader en ${item.sector}.`,
113→            probability: Math.max(score - 10, 50)
114→        }
115→    };
116→  };
117→
118→  const handleViewDetails = (item: typeof DIRECTORY_DATA[0]) => {
119→      const mockResult = generateMockAnalysis(item);
120→      onViewEntity(mockResult);
121→  };
122→
123→  // --- COMPOSANT : VUE NAVIGATEUR (Inspiré AI Peekaboo) ---
124→  const renderBrowser = () => (
125→    <div className="space-y-8 animate-in fade-in duration-500">
126→        <div className="text-center space-y-4 mb-12">
127→            <h1 className="text-4xl md:text-5xl font-serif font-bold text-white">
128→              Annuaire <span className="text-primary italic">Knowledge Graph</span>
129→            </h1>
130→            <p className="text-gray-400 text-lg max-w-2xl mx-auto">
131→              Explorez les entités certifiées AEO. Ces entreprises ont structuré leurs données pour être citées en priorité par ChatGPT, Claude et Gemini.
132→            </p>
133→            <div className="flex justify-center gap-4 pt-4">
134→                <button 
135→                    onClick={onNavigateToPlan}
136→                    className="px-6 py-3 bg-primary hover:bg-emerald-600 text-black font-bold rounded-xl transition-all shadow-lg shadow-primary/20 flex items-center gap-2 transform hover:scale-105"
137→                >
138→                    <Sparkles size={18} /> Rejoindre l'Index
139→                </button>
140→            </div>
141→        </div>
142→
143→        {/* Search & Filters */}
144→        <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white/5 p-4 rounded-2xl border border-white/10">
145→            <div className="relative w-full md:w-96">
146→                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
147→                <input 
148→                    type="text" 
149→                    placeholder="Rechercher une entité..." 
150→                    className="w-full bg-black/40 border border-white/10 rounded-xl pl-10 pr-4 py-2.5 text-white focus:border-primary/50 outline-none"
151→                    value={searchTerm}
152→                    onChange={(e) => setSearchTerm(e.target.value)}
153→                />
154→            </div>
155→            <div className="flex gap-2 overflow-x-auto w-full md:w-auto no-scrollbar pb-2 md:pb-0">
156→                {uniqueSectors.map(sector => (
157→                    <button
158→                        key={sector}
159→                        onClick={() => setSelectedFilter(sector)}
160→                        className={`px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-colors ${selectedFilter === sector ? 'bg-white/20 text-white' : 'bg-transparent text-gray-400 hover:bg-white/5'}`}
161→                    >
162→                        {sector}
163→                    </button>
164→                ))}
165→            </div>
166→        </div>
167→
168→        {/* Grid des Entités */}
169→        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
170→            
171→            {/* Upsell Card - NOW FIRST */}
172→            <div className="border border-dashed border-white/20 rounded-2xl p-6 flex flex-col items-center justify-center text-center hover:bg-white/5 transition-colors cursor-pointer group" onClick={onNavigateToPlan}>
173→                <div className="w-16 h-16 rounded-full bg-white/5 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
174→                    <Plus size={32} className="text-gray-400 group-hover:text-white" />
175→                </div>
176→                <h3 className="font-bold text-white mb-1">Votre entreprise ici ?</h3>
177→                <p className="text-sm text-gray-500 mb-4">Rejoignez l'index et boostez votre visibilité IA.</p>
178→                <span className="text-primary text-sm font-bold flex items-center gap-1 group-hover:underline">
179→                    Ajouter mon site <ArrowRight size={14} />
180→                </span>
181→            </div>
182→
183→            {filteredDirectory.map((item) => (
184→                <div key={item.id} className="glass-panel p-6 rounded-2xl border border-white/10 group hover:border-primary/30 transition-all hover:-translate-y-1 flex flex-col">
185→                    <div className="flex justify-between items-start mb-4">
186→                        <div className="flex items-center gap-3">
187→                            <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-gray-800 to-black border border-white/10 flex items-center justify-center text-white font-bold font-serif text-xl shadow-inner">
188→                                {item.name.charAt(0)}
189→                            </div>
190→                            <div>
191→                                <h3 className="font-bold text-white flex items-center gap-1">
192→                                    {item.name} 
193→                                    {item.verified && <Check size={14} className="text-primary" />}
194→                                </h3>
195→                                <p className="text-xs text-gray-500">{item.sector}</p>
196→                            </div>
197→                        </div>
198→                        <div className="flex flex-col items-end">
199→                            <div className={`text-lg font-bold ${item.aeoScore >= 90 ? 'text-emerald-400' : 'text-amber-400'}`}>
200→                                {item.aeoScore}
201→                            </div>
202→                            <div className="text-[10px] text-gray-500 uppercase tracking-wider">AEO Score</div>
203→                        </div>
204→                    </div>
205→                    
206→                    <p className="text-sm text-gray-400 mb-6 line-clamp-2 h-10">
207→                        {item.desc}
208→                    </p>
209→
210→                    <div className="flex items-center justify-between pt-4 border-t border-white/5 mt-auto">
211→                        <span className={`text-xs px-2 py-1 rounded border ${
212→                            item.status === 'Elite' ? 'bg-purple-500/10 border-purple-500/30 text-purple-400' :
213→                            item.status === 'Premium' ? 'bg-blue-500/10 border-blue-500/30 text-blue-400' :
214→                            'bg-gray-500/10 border-gray-500/30 text-gray-400'
215→                        }`}>
216→                            {item.status} Member
217→                        </span>
218→                        <button 
219→                            onClick={() => handleViewDetails(item)}
220→                            className="text-xs text-white hover:text-primary flex items-center gap-1 transition-colors"
221→                        >
222→                            Voir la fiche <ArrowRight size={12} />
223→                        </button>
224→                    </div>
225→                </div>
226→            ))}
227→        </div>
228→    </div>
229→  );
230→
231→  // --- COMPOSANT : TUNNEL D'INSCRIPTION (Conservé mais inactif via l'UI actuelle) ---
232→  const renderJoinFunnel = () => (
233→    <>
234→      <div className="mb-8">
235→        <button onClick={() => setViewMode('browse')} className="flex items-center text-sm text-gray-400 hover:text-white mb-4 transition-colors">
236→            <ArrowLeft size={16} className="mr-2" /> Retour à l'annuaire
237→        </button>
238→        <h2 className="text-3xl font-serif font-bold text-white mb-2">Rejoindre CitedBy Index</h2>
239→        <div className="flex items-center gap-2">
240→            <div className={`h-1 w-8 rounded-full ${step === 'intro' ? 'bg-primary' : 'bg-gray-700'}`}></div>
241→            <div className={`h-1 w-8 rounded-full ${step === 'form' ? 'bg-primary' : 'bg-gray-700'}`}></div>
242→            <div className={`h-1 w-8 rounded-full ${step === 'payment' ? 'bg-primary' : 'bg-gray-700'}`}></div>
243→        </div>
244→      </div>
245→      {/* ... Content of join funnel kept for potential future use ... */}
246→      <div className="text-center py-20 text-gray-500">
247→          Redirection vers la page Plan en cours...
248→      </div>
249→    </>
250→  );
251→
252→  return (
253→    <div className="max-w-6xl mx-auto px-4 py-10 animate-in fade-in duration-500 min-h-[80vh]">
254→      
255→      {viewMode === 'browse' ? (
256→          <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
257→            <ArrowLeft size={18} className="mr-2" /> Retour
258→          </button>
259→      ) : null}
260→
261→      {/* VIEW SWITCHING LOGIC */}
262→      {viewMode === 'browse' ? renderBrowser() : renderJoinFunnel()}
263→
264→    </div>
265→  );
266→};
267→
268→export default Directory;
269→

  1→import React from 'react';
  2→import { PenTool, FileText, Code, FileCode, Search, Sparkles, AlertTriangle, Feather, Shield, Bot } from 'lucide-react';
  3→import { useTranslation } from '../i18n';
  4→
  5→interface GenerativeToolsProps {
  6→  onNavigate: (view: any) => void;
  7→}
  8→
  9→interface ToolCardProps {
 10→  icon: React.ElementType;
 11→  label: string;
 12→  desc: string;
 13→  color: string;
 14→  bg: string;
 15→  onClick: () => void;
 16→}
 17→
 18→const ToolCard: React.FC<ToolCardProps> = ({ icon: Icon, label, desc, color, bg, onClick }) => (
 19→  <button
 20→    onClick={onClick}
 21→    className="bg-[#1a1d21] border border-white/5 rounded-2xl p-8 flex flex-col items-center justify-center gap-6 hover:bg-white/5 transition-all hover:-translate-y-1 group h-full shadow-lg hover:shadow-xl hover:border-white/10"
 22→  >
 23→    <div className={`p-5 rounded-2xl ${bg} group-hover:scale-110 transition-transform duration-300`}>
 24→      <Icon size={48} className={color} />
 25→    </div>
 26→    <div className="text-center space-y-2">
 27→      <span className="block text-xl font-bold text-gray-200 group-hover:text-white transition-colors">{label}</span>
 28→      <span className="block text-sm text-gray-500 group-hover:text-gray-400 transition-colors">{desc}</span>
 29→    </div>
 30→  </button>
 31→);
 32→
 33→const GenerativeTools: React.FC<GenerativeToolsProps> = ({ onNavigate }) => {
 34→  const { t } = useTranslation();
 35→
 36→  const tools = [
 37→    { id: 'smc-studio', label: t.generativeTools.smcStudio, icon: PenTool, color: 'text-orange-400', bg: 'bg-orange-500/10', desc: t.generativeTools.smcStudioDesc },
 38→    { id: 'content-writer', label: t.generativeTools.contentWriter, icon: Feather, color: 'text-rose-400', bg: 'bg-rose-500/10', desc: t.generativeTools.contentWriterDesc },
 39→    { id: 'reputation', label: t.generativeTools.reputation, icon: Shield, color: 'text-amber-400', bg: 'bg-amber-500/10', desc: t.generativeTools.reputationDesc },
 40→    { id: 'source-of-truth', label: t.generativeTools.sourceOfTruth, icon: FileText, color: 'text-purple-400', bg: 'bg-purple-500/10', desc: t.generativeTools.sourceOfTruthDesc },
 41→    { id: 'schema-org', label: t.generativeTools.schemaOrg, icon: Code, color: 'text-blue-400', bg: 'bg-blue-500/10', desc: t.generativeTools.schemaOrgDesc },
 42→    { id: 'robots-txt', label: t.generativeTools.robotsTxt, icon: FileCode, color: 'text-emerald-400', bg: 'bg-emerald-500/10', desc: t.generativeTools.robotsTxtDesc },
 43→    { id: 'bot-tracking', label: t.generativeTools.botTracking || 'Suivi Bots IA', icon: Bot, color: 'text-cyan-400', bg: 'bg-cyan-500/10', desc: t.generativeTools.botTrackingDesc || 'Activation & suivi des crawlers' },
 44→  ];
 45→
 46→  return (
 47→    <div className="max-w-[1400px] mx-auto px-6 py-8 animate-in fade-in duration-500">
 48→
 49→      {/* Header style Dashboard Pro */}
 50→      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
 51→        <div className="flex items-center gap-4">
 52→          <h1 className="text-3xl font-bold text-white">{t.generativeTools.title}</h1>
 53→          <span className="bg-primary/10 text-primary text-xs font-bold px-3 py-1 rounded-full border border-primary/20 flex items-center gap-1">
 54→            <Sparkles size={12} /> {t.generativeTools.suitePro}
 55→          </span>
 56→        </div>
 57→
 58→        <div className="flex items-center gap-4 w-full md:w-auto">
 59→          <div className="relative flex-1 md:flex-none">
 60→            <input
 61→              type="text"
 62→              placeholder={t.generativeTools.searchPlaceholder}
 63→              className="bg-[#1a1d21] border border-white/10 rounded-lg py-2.5 pl-4 pr-10 text-sm text-gray-300 focus:outline-none focus:border-primary w-full md:w-80 transition-all"
 64→            />
 65→            <Search size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500" />
 66→          </div>
 67→        </div>
 68→      </div>
 69→
 70→      {/* Grid des Outils */}
 71→      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
 72→        {tools.map((tool) => (
 73→            <ToolCard
 74→                key={tool.id}
 75→                icon={tool.icon}
 76→                label={tool.label}
 77→                desc={tool.desc}
 78→                color={tool.color}
 79→                bg={tool.bg}
 80→                onClick={() => onNavigate(tool.id)}
 81→            />
 82→        ))}
 83→      </div>
 84→
 85→      {/* Section Explicative */}
 86→      <div className="p-8 bg-[#1a1d21] border border-white/5 rounded-2xl">
 87→        <div className="flex items-center gap-3 mb-6">
 88→            <div className="p-2 bg-white/5 rounded-lg">
 89→                <AlertTriangle size={20} className="text-yellow-400" />
 90→            </div>
 91→            <h3 className="text-xl font-bold text-white">{t.generativeTools.whyUse}</h3>
 92→        </div>
 93→
 94→        <div className="grid md:grid-cols-3 gap-8">
 95→            <div className="space-y-3">
 96→                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.structuredContent}</h4>
 97→                <p className="text-sm text-gray-400 leading-relaxed">
 98→                    {t.generativeTools.structuredContentDesc}
 99→                </p>
100→            </div>
101→            <div className="space-y-3">
102→                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.technicalData}</h4>
103→                <p className="text-sm text-gray-400 leading-relaxed">
104→                    {t.generativeTools.technicalDataDesc}
105→                </p>
106→            </div>
107→            <div className="space-y-3">
108→                <h4 className="font-bold text-gray-200 text-lg">{t.generativeTools.sourceAuthority}</h4>
109→                <p className="text-sm text-gray-400 leading-relaxed">
110→                    {t.generativeTools.sourceAuthorityDesc}
111→                </p>
