181→                  <div className="flex items-center gap-2 text-sm font-medium text-white">
182→                    {mode === 'article' ? <Bot size={16} className="text-emerald-400" /> : <FileText size={16} className="text-pink-400" />} 
183→                    {mode === 'article' ? 'Article Rédigé par IA' : 'Brief Généré'}
184→                  </div>
185→                  <div className="flex gap-2">
186→                    <button onClick={handleCopy} className="flex items-center gap-2 px-3 py-1.5 bg-white/5 hover:bg-white/10 rounded-lg text-xs font-medium text-white border border-white/10 transition-colors">
187→                      {copied ? <Check size={14} className="text-emerald-400" /> : <Copy size={14} />}
188→                      {copied ? 'Copié' : 'Copier'}
189→                    </button>
190→                    <button onClick={handleDownload} className="flex items-center gap-2 px-3 py-1.5 bg-white text-black hover:bg-gray-200 rounded-lg text-xs font-bold transition-colors">
191→                      <Download size={14} /> Télécharger MD
192→                    </button>
193→                  </div>
194→                </div>
195→                
196→                {/* Markdown Content */}
197→                <div className="flex-1 overflow-auto p-8 bg-[#0a0a0f] custom-scrollbar">
198→                  {isWritingArticle ? (
199→                    <div className="h-full flex flex-col items-center justify-center space-y-4">
200→                        <Loader2 className="animate-spin text-pink-500" size={48} />
201→                        <p className="text-gray-400 animate-pulse">Rédaction de l'article optimisé en cours...</p>
